import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class NoConsecutiveBlankLinesRuleReproductionTest {
    private val noConsecutiveBlankLinesRuleAssertThat = assertThatRule { NoConsecutiveBlankLinesRule() }

    @Test
    fun `Given a class without body followed by consecutive blank lines at end of file then do not throw NPE`() {
        val code =
            """
            sealed class Hello


            """.trimIndent()
        // The issue is that it throws NPE, so if it doesn't throw, the test passes (or fails on lint violations if we expect them)
        noConsecutiveBlankLinesRuleAssertThat(code)
            .hasLintViolation(2, 1, "Needless blank line(s)")
            .isFormattedAs(
                """
                sealed class Hello
                """.trimIndent()
            )
    }
}
"}

